// Input validation helpers for API endpoints.
//
// Each helper appends a human-readable message to the `errors` array when a
// check fails and returns nothing. Route handlers build up an `errors` array,
// run all relevant checks, and if non-empty respond with 400 and the list.
//
// Keeping validators side-effecting on a shared array (rather than throwing)
// means a single request surfaces *every* problem at once instead of only the
// first one, which is friendlier for API consumers.

// RFC 5321 caps the full email address at 254 octets. A permissive but
// structurally strict regex: one or more non-whitespace/non-@ chars, an @,
// a domain label, a dot, and a TLD of at least two chars.
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/;

const NAME_MIN = 1;
const NAME_MAX = 100;
const EMAIL_MAX = 254;

/**
 * Verify that every field in `requiredFields` is present (not undefined/null)
 * on `obj`. Missing fields are reported individually so the client sees the
 * complete list in one response.
 */
function validateRequired(obj, requiredFields, errors) {
  if (obj === undefined || obj === null) {
    errors.push('request body is required');
    // Still report each missing field so the caller knows the full contract.
    for (const field of requiredFields) {
      errors.push(`'${field}' is required`);
    }
    return;
  }
  for (const field of requiredFields) {
    if (obj[field] === undefined || obj[field] === null || obj[field] === '') {
      errors.push(`'${field}' is required`);
    }
  }
}

/**
 * Validate that `value` represents a positive integer id. Accepts both number
 * and numeric-string forms (common when the id arrives as a path/query param).
 */
function validateId(value, fieldName, errors) {
  if (value === undefined || value === null || value === '') {
    // `validateRequired` already reports absence; skip to avoid duplicates.
    return;
  }
  const n = Number(value);
  if (!Number.isFinite(n) || !Number.isInteger(n) || n <= 0) {
    errors.push(`'${fieldName}' must be a positive integer`);
  }
}

/**
 * Validate that `value` is a string and, if min/max supplied, within the
 * given length range. Pass `{ min, max }` in `opts`.
 */
function validateString(value, fieldName, errors, opts = {}) {
  if (value === undefined || value === null) {
    return;
  }
  if (typeof value !== 'string') {
    errors.push(`'${fieldName}' must be a string`);
    return;
  }
  const { min, max } = opts;
  if (min !== undefined && value.length < min) {
    errors.push(`'${fieldName}' must be at least ${min} character(s)`);
  }
  if (max !== undefined && value.length > max) {
    errors.push(`'${fieldName}' must be at most ${max} character(s)`);
  }
}

/**
 * Validate that `value` is a syntactically plausible email address and does
 * not exceed the RFC-mandated 254 character limit.
 */
function validateEmail(value, fieldName, errors) {
  if (value === undefined || value === null) {
    return;
  }
  if (typeof value !== 'string') {
    errors.push(`'${fieldName}' must be a string`);
    return;
  }
  if (value.length > EMAIL_MAX) {
    errors.push(`'${fieldName}' must be at most ${EMAIL_MAX} character(s)`);
  }
  if (!EMAIL_REGEX.test(value)) {
    errors.push(`'${fieldName}' must be a valid email address`);
  }
}

/**
 * Bundled validator for a user payload (name + email). Used by POST /users
 * and PUT /users/:id. If `partial` is true, absent fields are allowed (useful
 * for PATCH-style updates) — present fields are still fully validated.
 */
function validateUserPayload(body, errors, { partial = false } = {}) {
  if (!partial) {
    validateRequired(body, ['name', 'email'], errors);
  }
  if (body && body.name !== undefined) {
    validateString(body.name, 'name', errors, { min: NAME_MIN, max: NAME_MAX });
  }
  if (body && body.email !== undefined) {
    validateEmail(body.email, 'email', errors);
  }
}

/**
 * Express helper: if `errors` is non-empty, send a 400 response describing
 * every failed check and return true (so the caller can `return` early).
 */
function sendValidationError(res, errors) {
  if (errors.length === 0) return false;
  res.status(400).json({
    error: 'Validation failed',
    details: errors,
  });
  return true;
}

module.exports = {
  validateRequired,
  validateId,
  validateString,
  validateEmail,
  validateUserPayload,
  sendValidationError,
  // Exported for tests / reuse.
  EMAIL_REGEX,
  NAME_MIN,
  NAME_MAX,
  EMAIL_MAX,
};

