// Validation helper module
// Provides reusable field validators and a small runner that collects
// all failures so callers can return a descriptive 400 response.

// RFC 5321 caps the full address at 254 octets, which is the commonly
// referenced practical upper bound for email length.
const EMAIL_MAX_LENGTH = 254;
const NAME_MIN_LENGTH = 1;
const NAME_MAX_LENGTH = 100;

// Pragmatic email regex: requires a local part, an "@", a domain label,
// a dot, and a TLD of at least 2 chars. Not a full RFC 5322 parser, but
// sufficient for rejecting obviously malformed addresses.
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/;

function isPresent(value) {
  return value !== undefined && value !== null && value !== '';
}

function validateId(value, { field = 'id' } = {}) {
  if (!isPresent(value)) {
    return `${field} is required`;
  }
  // Accept numeric strings (e.g. from route params) as well as numbers.
  const asNumber = typeof value === 'number' ? value : Number(value);
  if (!Number.isFinite(asNumber) || !/^-?\d+$/.test(String(value).trim())) {
    return `${field} must be numeric`;
  }
  if (asNumber <= 0) {
    return `${field} must be a positive integer`;
  }
  return null;
}

function validateName(value, { field = 'name' } = {}) {
  if (!isPresent(value)) {
    return `${field} is required`;
  }
  if (typeof value !== 'string') {
    return `${field} must be a string`;
  }
  if (value.length < NAME_MIN_LENGTH || value.length > NAME_MAX_LENGTH) {
    return `${field} must be between ${NAME_MIN_LENGTH} and ${NAME_MAX_LENGTH} characters`;
  }
  return null;
}

function validateEmail(value, { field = 'email' } = {}) {
  if (!isPresent(value)) {
    return `${field} is required`;
  }
  if (typeof value !== 'string') {
    return `${field} must be a string`;
  }
  if (value.length > EMAIL_MAX_LENGTH) {
    return `${field} must be at most ${EMAIL_MAX_LENGTH} characters`;
  }
  if (!EMAIL_REGEX.test(value)) {
    return `${field} must be a valid email address`;
  }
  return null;
}

// Runs a map of `{ fieldName: validatorFn }` against a source object and
// returns an array of all error messages (empty if everything passed).
function runValidators(source, validators) {
  const errors = [];
  for (const [field, validator] of Object.entries(validators)) {
    const message = validator(source[field], { field });
    if (message) errors.push(message);
  }
  return errors;
}

// Express middleware factory. Usage:
//   app.post('/users', validateBody({ name: validateName, email: validateEmail }), handler)
function validateBody(schema) {
  return (req, res, next) => {
    const errors = runValidators(req.body || {}, schema);
    if (errors.length > 0) {
      return res.status(400).json({
        error: 'Validation failed',
        details: errors,
      });
    }
    next();
  };
}

function validateParams(schema) {
  return (req, res, next) => {
    const errors = runValidators(req.params || {}, schema);
    if (errors.length > 0) {
      return res.status(400).json({
        error: 'Validation failed',
        details: errors,
      });
    }
    next();
  };
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  runValidators,
  validateBody,
  validateParams,
  constants: {
    EMAIL_MAX_LENGTH,
    NAME_MIN_LENGTH,
    NAME_MAX_LENGTH,
  },
};

