// validation.js
// Reusable input-validation helpers for the API.
//
// Each primitive validator returns either `null` (valid) or a string describing
// the failure. `runValidations` aggregates those strings and `validate` wraps it
// all up as Express middleware that short-circuits with a 400 + descriptive body
// when any validation fails.

// RFC 5321 caps the full address at 254 octets; we enforce the same ceiling.
const EMAIL_MAX_LENGTH = 254;
const NAME_MIN_LENGTH = 1;
const NAME_MAX_LENGTH = 100;

// Deliberately pragmatic — catches obvious garbage without trying to fully
// implement RFC 5322. Requires a local part, an '@', a domain, a '.', and a TLD.
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

function isPresent(value) {
  return value !== undefined && value !== null && value !== '';
}

function validateRequired(fieldName, value) {
  if (!isPresent(value)) {
    return `${fieldName} is required`;
  }
  return null;
}

function validateId(value, { fieldName = 'id' } = {}) {
  if (!isPresent(value)) {
    return `${fieldName} is required`;
  }
  // Accept numeric strings (route/query params arrive as strings) as well as
  // numbers. Reject floats, NaN, Infinity, and negative values.
  const asNumber = typeof value === 'number' ? value : Number(value);
  if (!Number.isFinite(asNumber)) {
    return `${fieldName} must be numeric`;
  }
  if (!Number.isInteger(asNumber)) {
    return `${fieldName} must be an integer`;
  }
  if (asNumber <= 0) {
    return `${fieldName} must be a positive integer`;
  }
  return null;
}

function validateName(value, { fieldName = 'name', required = true } = {}) {
  if (!isPresent(value)) {
    return required ? `${fieldName} is required` : null;
  }
  if (typeof value !== 'string') {
    return `${fieldName} must be a string`;
  }
  if (value.length < NAME_MIN_LENGTH || value.length > NAME_MAX_LENGTH) {
    return `${fieldName} must be between ${NAME_MIN_LENGTH} and ${NAME_MAX_LENGTH} characters`;
  }
  return null;
}

function validateEmail(value, { fieldName = 'email', required = true } = {}) {
  if (!isPresent(value)) {
    return required ? `${fieldName} is required` : null;
  }
  if (typeof value !== 'string') {
    return `${fieldName} must be a string`;
  }
  if (value.length > EMAIL_MAX_LENGTH) {
    return `${fieldName} must be at most ${EMAIL_MAX_LENGTH} characters`;
  }
  if (!EMAIL_REGEX.test(value)) {
    return `${fieldName} must be a valid email address`;
  }
  return null;
}

// Run a list of validator thunks and collect all non-null error messages.
// Every validator runs — we report every failure at once rather than bailing
// on the first one, so clients can fix everything in a single round-trip.
function runValidations(validators) {
  const errors = [];
  for (const validator of validators) {
    const err = validator();
    if (err) errors.push(err);
  }
  return errors;
}

// Express middleware factory. `buildValidators` receives the request and
// returns an array of validator thunks.
function validate(buildValidators) {
  return (req, res, next) => {
    const errors = runValidations(buildValidators(req));
    if (errors.length > 0) {
      return res.status(400).json({
        error: 'Validation failed',
        details: errors,
      });
    }
    return next();
  };
}

module.exports = {
  EMAIL_MAX_LENGTH,
  NAME_MIN_LENGTH,
  NAME_MAX_LENGTH,
  EMAIL_REGEX,
  isPresent,
  validateRequired,
  validateId,
  validateName,
  validateEmail,
  runValidations,
  validate,
};

