// validation.js
// Reusable input validation helpers for API route handlers.
//
// Each validator returns an array of error strings. An empty array means
// the input passed validation. Composed helpers (e.g. validateUserPayload)
// aggregate errors from multiple field checks so a single 400 response can
// report everything that was wrong with a request.

'use strict';

// RFC 5321 caps the full address at 254 characters. The regex below is a
// pragmatic check — it rejects obvious garbage without trying to be a full
// RFC 5322 parser.
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const EMAIL_MAX_LENGTH = 254;
const NAME_MIN_LENGTH = 1;
const NAME_MAX_LENGTH = 100;

/**
 * Ensure a value is present (not undefined, not null, not an empty string).
 * @param {string} field - name of the field (used in the error message)
 * @param {*} value
 * @returns {string[]} array containing a single error if missing, else []
 */
function validateRequired(field, value) {
  if (value === undefined || value === null || value === '') {
    return [`${field} is required`];
  }
  return [];
}

/**
 * Validate that a value is (or parses cleanly to) a finite integer.
 * Accepts numbers and numeric strings; rejects floats, NaN, and non-numerics.
 * Returns the parsed number on success via the second tuple element.
 *
 * @param {string} field
 * @param {*} value
 * @returns {{errors: string[], value: number|null}}
 */
function validateNumericId(field, value) {
  if (value === undefined || value === null || value === '') {
    return { errors: [`${field} is required`], value: null };
  }
  const asNumber = typeof value === 'number' ? value : Number(value);
  if (!Number.isFinite(asNumber) || !Number.isInteger(asNumber)) {
    return { errors: [`${field} must be a numeric integer`], value: null };
  }
  if (asNumber < 0) {
    return { errors: [`${field} must be a non-negative integer`], value: null };
  }
  return { errors: [], value: asNumber };
}

/**
 * Validate a string field with min/max length constraints.
 *
 * @param {string} field
 * @param {*} value
 * @param {{min?: number, max?: number}} [opts]
 * @returns {string[]}
 */
function validateString(field, value, opts = {}) {
  const { min = 0, max = Infinity } = opts;
  if (typeof value !== 'string') {
    return [`${field} must be a string`];
  }
  const errors = [];
  if (value.length < min) {
    errors.push(`${field} must be at least ${min} character(s)`);
  }
  if (value.length > max) {
    errors.push(`${field} must be at most ${max} character(s)`);
  }
  return errors;
}

/**
 * Validate an email address: must be a string, <= 254 chars, and match
 * the email regex.
 *
 * @param {string} field
 * @param {*} value
 * @returns {string[]}
 */
function validateEmail(field, value) {
  if (typeof value !== 'string') {
    return [`${field} must be a string`];
  }
  const errors = [];
  if (value.length > EMAIL_MAX_LENGTH) {
    errors.push(`${field} must be at most ${EMAIL_MAX_LENGTH} character(s)`);
  }
  if (!EMAIL_REGEX.test(value)) {
    errors.push(`${field} must be a valid email address`);
  }
  return errors;
}

/**
 * Validate a full user payload (for POST /users and PUT /users/:id).
 * Required fields: name, email. Aggregates all field errors.
 *
 * @param {object} payload
 * @returns {string[]}
 */
function validateUserPayload(payload) {
  const errors = [];
  if (!payload || typeof payload !== 'object' || Array.isArray(payload)) {
    return ['request body must be a JSON object'];
  }

  // name
  if (payload.name === undefined || payload.name === null) {
    errors.push('name is required');
  } else {
    errors.push(
      ...validateString('name', payload.name, {
        min: NAME_MIN_LENGTH,
        max: NAME_MAX_LENGTH,
      }),
    );
  }

  // email
  if (payload.email === undefined || payload.email === null) {
    errors.push('email is required');
  } else {
    errors.push(...validateEmail('email', payload.email));
  }

  return errors;
}

/**
 * Express-style helper: if `errors` is non-empty, send a 400 with a
 * descriptive body and return true. Otherwise return false.
 *
 * @param {import('express').Response} res
 * @param {string[]} errors
 * @returns {boolean} whether a response was sent
 */
function sendValidationError(res, errors) {
  if (errors && errors.length > 0) {
    res.status(400).json({
      error: 'Validation failed',
      details: errors,
    });
    return true;
  }
  return false;
}

module.exports = {
  validateRequired,
  validateNumericId,
  validateString,
  validateEmail,
  validateUserPayload,
  sendValidationError,
  // exported for tests / reuse
  EMAIL_MAX_LENGTH,
  NAME_MIN_LENGTH,
  NAME_MAX_LENGTH,
};
